        interview_id, question_index, analysis_data,
        eye_contact_score, expression_score, body_language_score,
        voice_score, presentation_score
      )
      VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
      ON CONFLICT (interview_id, question_index)
      DO UPDATE SET
        analysis_data = $3,
        eye_contact_score = $4,
