   645→  <script>
   646→    // Video practice mode variables
   647→    let practiceMode = 'text';
   648→    let videoStream = null;
   649→    let videoRecorder = null;
   650→    let videoAnalyzer = null;
   651→    let recordedVideoBlob = null;
   652→    let practiceAnalysisData = null;
   653→
   654→    // Switch practice mode
   655→    function switchPracticeMode(mode) {
   656→      practiceMode = mode;
   657→
   658→      // Update toggle buttons
   659→      document.querySelectorAll('.mode-btn').forEach(btn => {
   660→        btn.classList.remove('active');
   661→        if (btn.dataset.mode === mode) {
   662→          btn.classList.add('active');
   663→        }
   664→      });
   665→
   666→      // Show/hide appropriate areas
   667→      if (mode === 'text') {
   668→        document.getElementById('text-response-area').style.display = 'block';
   669→        document.getElementById('video-response-area').classList.remove('active');
   670→
   671→        // Stop video if running
   672→        if (videoStream) {
   673→          videoStream.getTracks().forEach(track => track.stop());
   674→          videoStream = null;
   675→        }
   676→      } else {
   677→        document.getElementById('text-response-area').style.display = 'none';
   678→        document.getElementById('video-response-area').classList.add('active');
   679→      }
   680→    }
   681→
   682→    // Start video practice
   683→    async function startVideoPractice() {
   684→      try {
   685→        videoStream = await navigator.mediaDevices.getUserMedia({
   686→          video: { width: 1280, height: 720 },
   687→          audio: {
   688→            echoCancellation: true,
   689→            noiseSuppression: true,
   690→            autoGainControl: true
   691→          }
   692→        });
   693→
   694→        document.getElementById('practice-video').srcObject = videoStream;
   695→
   696→        // Verify audio tracks
   697→        const audioTracks = videoStream.getAudioTracks();
   698→        if (audioTracks.length === 0) {
   699→          console.error('No audio tracks in practice video stream');
   700→          alert('Microphone not detected. Video will record without audio.');
   701→        } else {
   702→          const track = audioTracks[0];
   703→          if (!track.enabled) track.enabled = true;
   704→          console.log('Practice mic active:', track.label);
   705→        }
   706→
   707→        // Initialize video analyzer if not already done
   708→        if (!videoAnalyzer) {
   709→          videoAnalyzer = new VideoAnalyzer();
   710→          await videoAnalyzer.init();
   711→
   712→          videoAnalyzer.on('scores', (scores) => {
   713→            document.getElementById('live-eye-contact').textContent = scores.eyeContact + '%';
   714→            document.getElementById('video-analysis-badge').style.display = 'block';
   715→          });
   716→        }
   717→
   718→        document.getElementById('start-video-btn').style.display = 'none';
   719→        document.getElementById('record-video-btn').style.display = 'inline-flex';
   720→      } catch (err) {
   721→        console.error('Camera/microphone error:', err);
   722→        alert('Camera and microphone access required for video practice. Please allow both permissions.');
   723→      }
   724→    }
   725→
   726→    // Record video practice
   727→    function recordVideoPractice() {
   728→      try {
   729→        // Use mimeType with both video AND audio codecs
   730→        let mimeType = 'video/webm;codecs=vp9,opus';
   731→        if (!MediaRecorder.isTypeSupported(mimeType)) {
   732→          mimeType = 'video/webm;codecs=vp8,opus';
   733→        }
   734→        if (!MediaRecorder.isTypeSupported(mimeType)) {
   735→          mimeType = 'video/webm';
   736→        }
   737→
   738→        // Verify audio tracks before recording
   739→        const audioTracks = videoStream.getAudioTracks();
   740→        if (audioTracks.length === 0 || !audioTracks[0].enabled) {
   741→          alert('Microphone is not active. Please check your mic permissions.');
   742→          return;
   743→        }
   744→
   745→        videoRecorder = new MediaRecorder(videoStream, { mimeType });
   746→
   747→        const chunks = [];
   748→        videoRecorder.ondataavailable = (e) => {
   749→          if (e.data.size > 0) chunks.push(e.data);
   750→        };
   751→
   752→        videoRecorder.onstop = () => {
   753→          recordedVideoBlob = new Blob(chunks, { type: 'video/webm' });
   754→          practiceAnalysisData = videoAnalyzer ? videoAnalyzer.getFinalAnalysis() : null;
   755→
   756→          document.getElementById('record-video-btn').style.display = 'inline-flex';
   757→          document.getElementById('stop-video-btn').style.display = 'none';
   758→          document.getElementById('video-analysis-badge').style.display = 'none';
   759→        };
   760→
   761→        videoRecorder.start();
   762→
   763→        if (videoAnalyzer) {
   764→          videoAnalyzer.reset();
   765→          videoAnalyzer.startAnalysis(document.getElementById('practice-video'), 500);
   766→        }
   767→
   768→        document.getElementById('record-video-btn').style.display = 'none';
   769→        document.getElementById('stop-video-btn').style.display = 'inline-flex';
   770→      } catch (err) {
   771→        console.error('Recording error:', err);
   772→        alert('Failed to start recording.');
   773→      }
   774→    }
   775→
   776→    // Stop video practice
   777→    function stopVideoPractice() {
   778→      if (videoRecorder && videoRecorder.state !== 'inactive') {
   779→        videoRecorder.stop();
   780→
   781→        if (videoAnalyzer) {
   782→          videoAnalyzer.stopAnalysis();
   783→        }
   784→      }
   785→    }
   786→
   787→    // Override submitPracticeResponse to handle video mode
   788→    const originalSubmit = submitPracticeResponse;
   789→    submitPracticeResponse = async function() {
   790→      if (practiceMode === 'video') {
   791→        if (!recordedVideoBlob) {
   792→          alert('Please record a video response first.');
   793→          return;
   794→        }
   795→
   796→        showLoading('AI is analyzing your video response...');
   797→
   798→        try {
   799→          // For now, just display coaching based on video analysis
   800→          hideLoading();
   801→          displayVideoPracticeCoaching();
   802→        } catch (err) {
   803→          hideLoading();
   804→          alert('Failed to analyze video: ' + err.message);
   805→        }
   806→      } else {
   807→        originalSubmit();
   808→      }
   809→    };
   810→
   811→    // Display video practice coaching
   812→    function displayVideoPracticeCoaching() {
   813→      if (!practiceAnalysisData) {
   814→        alert('No analysis data available.');
   815→        return;
   816→      }
   817→
   818→      const scores = practiceAnalysisData.scores;
   819→      const resultContainer = document.getElementById('coaching-result');
   820→
   821→      const insights = [];
   822→
   823→      if (scores.eyeContact >= 70) {
   824→        insights.push('✅ Strong eye contact maintained throughout');
   825→      } else {
   826→        insights.push('💡 Practice looking directly at the camera lens');
   827→      }
   828→
   829→      if (scores.bodyLanguage >= 70) {
   830→        insights.push('✅ Good posture and head stability');
   831→      } else {
   832→        insights.push('💡 Keep your head steady and maintain good posture');
   833→      }
   834→
   835→      if (scores.presentation >= 70) {
   836→        insights.push('✅ Excellent overall video presence');
   837→      } else {
   838→        insights.push('💡 Practice recording yourself to improve presence');
   839→      }
   840→
   841→      resultContainer.innerHTML = `
   842→        <div class="score-display">
