let currentAnalysis = null;
let editMode = false;
let editJobId = null;
let screeningQuestions = [];
let questionCounter = 0;

const COMMON_QUESTIONS = {
  work_auth: { type: 'yes_no', question: 'Are you legally authorized to work in the United States?', required: true },
  sponsorship: { type: 'yes_no', question: 'Will you now or in the future require visa sponsorship?', required: true },
  experience: { type: 'number', question: 'How many years of relevant experience do you have?', required: true, placeholder: 'e.g. 5' },
  salary: { type: 'text', question: 'What are your salary expectations for this role?', required: false, placeholder: 'e.g. $120,000 - $150,000' },
  start_date: { type: 'text', question: 'When is the earliest you could start?', required: false, placeholder: 'e.g. 2 weeks notice' },
  remote: { type: 'select', question: 'What is your preferred work arrangement?', required: true, options: ['On-site', 'Hybrid', 'Remote only', 'Flexible'] },
  relocation: { type: 'yes_no', question: 'Are you willing to relocate for this position?', required: false }
};

function addCommonQuestion(key) {
  const q = COMMON_QUESTIONS[key];
  if (!q) return;
  // Don't add duplicate common questions
  if (screeningQuestions.some(sq => sq.question === q.question)) return;
  screeningQuestions.push({ ...q, id: `sq_${++questionCounter}` });
  renderScreeningQuestions();
}

function addScreeningQuestion(type) {
  screeningQuestions.push({
    id: `sq_${++questionCounter}`,
    type,
    question: '',
    required: true,
    options: type === 'select' ? ['Option 1', 'Option 2'] : undefined,
    placeholder: type === 'number' ? 'Enter a number' : ''
  });
  renderScreeningQuestions();
}

function removeScreeningQuestion(id) {
  screeningQuestions = screeningQuestions.filter(q => q.id !== id);
  renderScreeningQuestions();
}

function renderScreeningQuestions() {
  const container = document.getElementById('screening-questions-list');
  if (screeningQuestions.length === 0) {
    container.innerHTML = '<p style="color: var(--text-muted); font-size: 13px; padding: 12px 0;">No screening questions added yet.</p>';
    return;
  }

  container.innerHTML = screeningQuestions.map((q, i) => `
    <div class="screening-question-item" data-id="${q.id}">
      <div class="sq-header">
        <span class="sq-number">${i + 1}</span>
        <span class="sq-type-badge">${q.type === 'yes_no' ? 'Yes/No' : q.type === 'select' ? 'Multiple Choice' : q.type === 'number' ? 'Numeric' : 'Short Answer'}</span>
        <label class="sq-required-toggle">
          <input type="checkbox" ${q.required ? 'checked' : ''} onchange="toggleRequired('${q.id}', this.checked)">
          <span>Required</span>
        </label>
        <button type="button" class="sq-remove" onclick="removeScreeningQuestion('${q.id}')" title="Remove">✕</button>
      </div>
      <input type="text" class="sq-question-input" value="${(q.question || '').replace(/"/g, '&quot;')}"
             placeholder="Enter your question..."
             onchange="updateQuestion('${q.id}', 'question', this.value)">
      ${q.type === 'select' ? `
        <div class="sq-options">
          ${(q.options || []).map((opt, oi) => `
            <div class="sq-option-row">
              <input type="text" value="${opt.replace(/"/g, '&quot;')}" placeholder="Option ${oi + 1}"
                     onchange="updateOption('${q.id}', ${oi}, this.value)">
              <button type="button" class="sq-option-remove" onclick="removeOption('${q.id}', ${oi})">✕</button>
            </div>
          `).join('')}
          <button type="button" class="btn btn-ghost btn-xs" onclick="addOption('${q.id}')">+ Add Option</button>
        </div>
      ` : ''}
    </div>
  `).join('');
}

function toggleRequired(id, val) {
  const q = screeningQuestions.find(q => q.id === id);
  if (q) q.required = val;
}

function updateQuestion(id, field, value) {
  const q = screeningQuestions.find(q => q.id === id);
  if (q) q[field] = value;
}

function updateOption(id, index, value) {
  const q = screeningQuestions.find(q => q.id === id);
  if (q && q.options) q.options[index] = value;
}

function addOption(id) {
  const q = screeningQuestions.find(q => q.id === id);
  if (q && q.options) {
    q.options.push('');
    renderScreeningQuestions();
  }
}

function removeOption(id, index) {
  const q = screeningQuestions.find(q => q.id === id);
  if (q && q.options && q.options.length > 2) {
    q.options.splice(index, 1);
    renderScreeningQuestions();
  }
}

function getScreeningQuestionsData() {
  return screeningQuestions.filter(q => q.question && q.question.trim()).map(q => ({
    id: q.id,
    type: q.type,
    question: q.question.trim(),
    required: q.required,
    options: q.options,
    placeholder: q.placeholder
  }));
}

