async function submitApplication() {
  const coverLetter = document.getElementById('cover-letter').value;
  const btn = document.getElementById('submit-apply-btn');

  // Collect screening answers
  const job = allJobs.find(j => j.id === selectedJobId) || savedJobs.find(j => j.id === selectedJobId);
  const questions = (job && job.screening_questions) || [];
  const screening_answers = {};

  for (const q of questions) {
    let val;
    if (q.type === 'yes_no') {
      const checked = document.querySelector(`input[name="sq_${q.id}"]:checked`);
      val = checked ? checked.value : '';
    } else {
      const el = document.getElementById(`sq_${q.id}`);
      val = el ? el.value.trim() : '';
    }

    if (q.required && !val) {
      alert(`Please answer: "${q.question}"`);
      return;
    }
    screening_answers[q.id] = val;
  }

  btn.textContent = 'Submitting...';
  btn.disabled = true;

  try {
    const data = await apiCall(`/candidate/jobs/${selectedJobId}/apply`, {
      method: 'POST',
      body: JSON.stringify({ cover_letter: coverLetter, screening_answers })
    });

