container.innerHTML = filtered.map(app => {
  // Build screening answers display
  let screeningHTML = '';
  const answers = typeof app.screening_answers === 'string' ? JSON.parse(app.screening_answers || '{}') : (app.screening_answers || {});
  const questions = typeof app.screening_questions === 'string' ? JSON.parse(app.screening_questions || '[]') : (app.screening_questions || []);

  if (questions.length > 0 && Object.keys(answers).length > 0) {
    screeningHTML = `
      <div class="screening-answers">
        <div class="screening-label">📋 Screening Answers</div>
        <div class="screening-grid">
          ${questions.map(q => {
            const ans = answers[q.id] || '-';
            return `<div class="screening-item">
              <span class="sq-label">${q.question}</span>
              <span class="sq-value ${q.type === 'yes_no' ? (ans === 'yes' ? 'sq-yes' : 'sq-no') : ''}">${ans}</span>
            </div>`;
          }).join('')}
        </div>
      </div>
    `;
  }

  // Build candidate insights badges
  let insightsHTML = '';
  if (app.verified_skills_count > 0 || app.best_interview_score || app.completed_interviews > 0) {
    insightsHTML = `<div class="candidate-insights">
      ${app.verified_skills_count > 0 ? `<span class="insight-badge skill-badge">✓ ${app.verified_skills_count} Verified Skill${app.verified_skills_count > 1 ? 's' : ''}</span>` : ''}
      ${app.best_interview_score ? `<span class="insight-badge interview-badge">🎤 Interview: ${app.best_interview_score}/10</span>` : ''}
      ${app.completed_interviews > 0 ? `<span class="insight-badge practice-badge">📝 ${app.completed_interviews} Mock Interview${app.completed_interviews > 1 ? 's' : ''}</span>` : ''}
    </div>`;
  }

  return `
  <div class="application-card">
    <div class="application-header">
      <div class="candidate-info">
        <div class="candidate-avatar">${(app.candidate_name || 'U').charAt(0).toUpperCase()}</div>
        <div class="candidate-details">
          <h3>${app.candidate_name || 'Unknown'}</h3>
          <p>${app.job_title || 'Position'}</p>
        </div>
      </div>
      <div class="application-meta">
        ${app.omniscore_at_apply ? `<span class="omniscore-badge">${app.omniscore_at_apply} OmniScore</span>` : ''}
        <span class="status-badge ${app.status}">${app.status}</span>
      </div>
    </div>
    <div class="application-body">
      <div class="application-info">
        <span class="info-item">📧 ${app.candidate_email || 'No email'}</span>
        <span class="info-item">📅 Applied ${formatDate(app.applied_at)}</span>
        ${app.match_score ? `<span class="info-item">🎯 ${app.match_score}% Match</span>` : ''}
      </div>
      ${insightsHTML}
      ${app.cover_letter ? `<p class="cover-letter-preview">${app.cover_letter.substring(0, 150)}...</p>` : ''}
      ${screeningHTML}
    </div>
    <div class="application-actions">
      <button onclick="updateStatus(${app.id}, 'reviewing')" class="btn btn-ghost btn-sm" ${app.status !== 'applied' ? 'disabled' : ''}>
        Review
      </button>
      <button onclick="scheduleInterview(${app.id})" class="btn btn-ghost btn-sm">
        Schedule Interview
      </button>
      <button onclick="makeOffer(${app.id}, ${app.candidate_id}, '${(app.candidate_name || '').replace(/'/g, "\\'")}', '${(app.candidate_email || '').replace(/'/g, "\\'")}', ${app.job_id}, '${(app.job_title || '').replace(/'/g, "\\'")}')" class="btn btn-primary btn-sm" ${app.status === 'offered' || app.status === 'hired' ? 'disabled' : ''}>
        Make Offer
      </button>
      <button onclick="updateStatus(${app.id}, 'rejected')" class="btn btn-ghost btn-sm danger">
        Reject
      </button>
    </div>
  </div>
`}).join('');

