/* Candidate Insights Badges */
.candidate-insights {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
  margin-bottom: 12px;
}

.insight-badge {
  padding: 3px 10px;
  border-radius: var(--radius-full);
  font-size: 11px;
  font-weight: 600;
}

.skill-badge { background: rgba(16, 185, 129, 0.15); color: #10b981; }
.interview-badge { background: rgba(139, 92, 246, 0.15); color: #a78bfa; }
.practice-badge { background: rgba(59, 130, 246, 0.15); color: #60a5fa; }

/* Screening Answers */
.screening-answers {
  margin-top: 12px;
  padding: 12px 16px;
  background: var(--bg-elevated);
  border-radius: var(--radius-md);
  border: 1px solid var(--border-color);
}

.screening-label {
  font-size: 13px;
  font-weight: 600;
  margin-bottom: 10px;
  color: var(--text-secondary);
}

.screening-grid {
  display: grid;
  gap: 8px;
}

.screening-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  font-size: 13px;
}

.sq-q { color: var(--text-muted); flex: 1; }
.sq-a { font-weight: 600; color: var(--text-primary); text-align: right; }
.sq-a.sq-yes { color: #10b981; }
.sq-a.sq-no { color: #ef4444; }

